package cmd

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"runtime"
	"strings"
	"sync"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
	"github.com/spf13/cobra"
	"github.com/stretchr/testify/require"
)

// TestMain clears all GIT_* environment variables before running tests so
// that tests invoking git commands operate on their own temp-dir repositories
// rather than any repository inherited from a hook invocation (e.g. GIT_DIR
// set by lefthook during pre-commit). Prefix scrub is important — lefthook
// sets GIT_AUTHOR_NAME, GIT_COMMITTER_EMAIL, GIT_CONFIG_PARAMETERS etc. that
// also leak into test subprocesses and corrupt the shared repo config.
func TestMain(m *testing.M) {
	for _, kv := range os.Environ() {
		if strings.HasPrefix(kv, "GIT_") {
			if idx := strings.IndexByte(kv, '='); idx >= 0 {
				_ = os.Unsetenv(kv[:idx])
			}
		}
	}
	cleanupTemp := isolateCmdTestTempRoot()
	code := m.Run()
	cleanupTemp()
	os.Exit(code)
}

func isolateCmdTestTempRoot() func() {
	tempRoot, err := os.MkdirTemp("", "ddx-cmd-tests-*")
	if err != nil {
		return func() {}
	}
	oldTmpDir, hadTmpDir := os.LookupEnv("TMPDIR")
	oldTmp, hadTmp := os.LookupEnv("TMP")
	_ = os.Setenv("TMPDIR", tempRoot)
	_ = os.Setenv("TMP", tempRoot)
	return func() {
		if hadTmpDir {
			_ = os.Setenv("TMPDIR", oldTmpDir)
		} else {
			_ = os.Unsetenv("TMPDIR")
		}
		if hadTmp {
			_ = os.Setenv("TMP", oldTmp)
		} else {
			_ = os.Unsetenv("TMP")
		}
		_ = os.RemoveAll(tempRoot)
	}
}

var (
	testLibraryPath string
	testLibraryOnce sync.Once
)

// GetTestLibraryPath returns the absolute path to a bare git repository
// that mimics a real upstream library (like GitHub). This is the ONLY way
// tests should get the test library path.
func GetTestLibraryPath() string {
	testLibraryOnce.Do(func() {
		// Find the test fixtures directory
		_, filename, _, _ := runtime.Caller(0)
		cmdDir := filepath.Dir(filename)
		fixtureDir := filepath.Join(cmdDir, "..", "test", "fixtures", "ddx-library")
		fixtureDir, _ = filepath.Abs(fixtureDir)

		// Determine base temp directory: TMP -> TMPDIR -> /tmp
		tempBase := "/tmp"
		if tmp := os.Getenv("TMP"); tmp != "" {
			tempBase = tmp
		} else if tmpdir := os.Getenv("TMPDIR"); tmpdir != "" {
			tempBase = tmpdir
		}

		workingRepo := filepath.Join(tempBase, ".test-library")
		bareRepo := filepath.Join(tempBase, ".test-library.git")
		testLibraryPath = bareRepo

		// Check if we need to recreate (fixtures changed or doesn't exist)
		needsRecreate := false
		if stat, err := os.Stat(bareRepo); err != nil || !stat.IsDir() {
			needsRecreate = true
		} else if os.Getenv("CI") == "" {
			// In local dev, check if any fixture is newer than the repo
			repoModTime := stat.ModTime()
			filepath.Walk(fixtureDir, func(path string, info os.FileInfo, err error) error {
				if err == nil && !info.IsDir() && info.ModTime().After(repoModTime) {
					needsRecreate = true
				}
				return nil
			})
		}

		if needsRecreate {
			// Clean up old repos
			os.RemoveAll(workingRepo)
			os.RemoveAll(bareRepo)

			// Create working repo and copy fixtures
			if err := os.MkdirAll(workingRepo, 0755); err != nil {
				panic(fmt.Sprintf("Failed to create working repo: %v", err))
			}

			if err := syncDirectory(fixtureDir, workingRepo); err != nil {
				panic(fmt.Sprintf("Failed to copy fixtures: %v", err))
			}

			// Initialize git repo
			cmds := []struct {
				args []string
				dir  string
			}{
				{[]string{"git", "init", "-b", "master"}, workingRepo},
				{[]string{"git", "config", "user.email", "test@example.com"}, workingRepo},
				{[]string{"git", "config", "user.name", "Test User"}, workingRepo},
				{[]string{"git", "add", "."}, workingRepo},
				{[]string{"git", "commit", "--allow-empty", "-m", "Test fixture"}, workingRepo},
				{[]string{"git", "init", "--bare", bareRepo}, ""},
				{[]string{"git", "remote", "add", "origin", bareRepo}, workingRepo},
				{[]string{"git", "push", "origin", "master"}, workingRepo},
			}

			for _, c := range cmds {
				cmd := exec.Command(c.args[0], c.args[1:]...)
				if c.dir != "" {
					cmd.Dir = c.dir
				}
				if output, err := cmd.CombinedOutput(); err != nil {
					panic(fmt.Sprintf("Failed to run %v: %v\nOutput: %s", c.args, err, output))
				}
			}
		}
	})
	return testLibraryPath
}

// syncDirectory copies files from src to dst, preserving directory structure
func syncDirectory(src, dst string) error {
	return filepath.Walk(src, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}

		// Skip .git directories from source
		if info.IsDir() && info.Name() == ".git" {
			return filepath.SkipDir
		}

		// Calculate relative path
		relPath, err := filepath.Rel(src, path)
		if err != nil {
			return err
		}

		dstPath := filepath.Join(dst, relPath)

		if info.IsDir() {
			return os.MkdirAll(dstPath, info.Mode())
		}

		// Copy file
		srcFile, err := os.Open(path)
		if err != nil {
			return err
		}
		defer func() { _ = srcFile.Close() }()

		dstFile, err := os.Create(dstPath)
		if err != nil {
			return err
		}
		defer func() { _ = dstFile.Close() }()

		if _, err := dstFile.ReadFrom(srcFile); err != nil {
			return err
		}

		return os.Chmod(dstPath, info.Mode())
	})
}

// TestEnvironment provides isolated testing environment for .ddx/config.yaml
type TestEnvironment struct {
	Dir            string
	ConfigPath     string
	LibraryPath    string
	TestLibraryURL string
	GitInitialized bool

	// Optional customizations
	Platform     string
	Architecture string
	HomeDir      string

	t *testing.T
}

// TestEnvOption is a functional option for configuring TestEnvironment
type TestEnvOption func(*TestEnvironment)

// WithGitInit controls whether to initialize a git repository
func WithGitInit(init bool) TestEnvOption {
	return func(te *TestEnvironment) {
		te.GitInitialized = init
	}
}

// WithPlatform sets the platform and architecture for installation tests
func WithPlatform(platform, arch string) TestEnvOption {
	return func(te *TestEnvironment) {
		te.Platform = platform
		te.Architecture = arch
	}
}

// WithHomeDir sets a custom home directory
func WithHomeDir(homeDir string) TestEnvOption {
	return func(te *TestEnvironment) {
		te.HomeDir = homeDir
	}
}

// WithCustomLibraryURL sets a custom library repository URL
func WithCustomLibraryURL(url string) TestEnvOption {
	return func(te *TestEnvironment) {
		te.TestLibraryURL = url
	}

	}
}

// NewTestEnvironment creates a clean test environment with temp directory
// By default: creates git repo, uses test-library fixture via file:// URL
func NewTestEnvironment(t *testing.T, opts ...TestEnvOption) *TestEnvironment {
	t.Helper()

	tempDir := t.TempDir()
	ddxDir := filepath.Join(tempDir, ".ddx")
	configPath := filepath.Join(ddxDir, "config.yaml")

	te := &TestEnvironment{
		Dir:            tempDir,
		ConfigPath:     configPath,
		LibraryPath:    filepath.Join(ddxDir, "library"),
		GitInitialized: true, // default: init git
		t:              t,
	}

	// Apply options
	for _, opt := range opts {
		opt(te)
	}

	// Set default test library URL if not customized
	if te.TestLibraryURL == "" {
		te.TestLibraryURL = "file://" + GetTestLibraryPath()
	}

	// Create .ddx directory
	require.NoError(t, os.MkdirAll(ddxDir, 0755))

	// Initialize git repository if requested
	if te.GitInitialized {
		te.initGit()
	}

	return te
}

// initGit initializes a git repository in the test directory
func (te *TestEnvironment) initGit() {
	te.t.Helper()

	// Strip inherited git env vars so git commands operate on the test
	// directory's own repository, not any repository inherited from a
	// hook or parent process (e.g. GIT_DIR set by lefthook).
	cleanEnv := gitpkg.CleanEnv()

	// git init
	gitInit := exec.Command("git", "init")
	gitInit.Dir = te.Dir
	gitInit.Env = cleanEnv
	require.NoError(te.t, gitInit.Run(), "git init should succeed")

	// git config user.email
	gitEmail := exec.Command("git", "config", "user.email", "test@example.com")
	gitEmail.Dir = te.Dir
	gitEmail.Env = cleanEnv
	require.NoError(te.t, gitEmail.Run(), "git config user.email should succeed")

	// git config user.name
	gitName := exec.Command("git", "config", "user.name", "Test User")
	gitName.Dir = te.Dir
	gitName.Env = cleanEnv
	require.NoError(te.t, gitName.Run(), "git config user.name should succeed")
}

// CreateConfig creates a config file with the given content
func (te *TestEnvironment) CreateConfig(content string) {
	te.t.Helper()
	require.NoError(te.t, os.WriteFile(te.ConfigPath, []byte(content), 0644))
}

// CreateDefaultConfig creates a minimal valid config file using test library
func (te *TestEnvironment) CreateDefaultConfig() {
	te.t.Helper()
	content := fmt.Sprintf(`version: "1.0"
library:
  path: .ddx/plugins/ddx
  repository:
    url: %s
    branch: master
persona_bindings: {}
`, te.TestLibraryURL)
	te.CreateConfig(content)
}

// CreateConfigWithCustomURL creates a config with a custom repository URL
func (te *TestEnvironment) CreateConfigWithCustomURL(url string) {
	te.t.Helper()
	content := fmt.Sprintf(`version: "1.0"
library:
  path: .ddx/plugins/ddx
  repository:
    url: %s
    branch: master
persona_bindings: {}
`, url)
	te.CreateConfig(content)
}

// RunCommand runs a DDx command in the test environment and returns output
func (te *TestEnvironment) RunCommand(args ...string) (string, error) {
	te.t.Helper()
	factory := NewCommandFactory(te.Dir)
	cmd := factory.NewRootCommand()
	cmd.SetArgs(args)

	var buf bytes.Buffer
	cmd.SetOut(&buf)
	cmd.SetErr(&buf)

	err := cmd.Execute()
	return buf.String(), err
}

// InitWithDDx properly initializes DDx in the test environment using ddx init
// If git is initialized, creates an initial commit before running ddx init.
// Otherwise uses --no-git flag. In CI environments, always uses --no-git.
func (te *TestEnvironment) InitWithDDx(flags ...string) {
	te.t.Helper()

	// Check if we should skip git operations
	hasNoGitFlag := false
	for _, flag := range flags {
		if flag == "--no-git" {
			hasNoGitFlag = true
			break
		}
	}

	// If git is initialized and we're not using --no-git, create initial commit
	if te.GitInitialized && !hasNoGitFlag {
		cleanEnv := gitpkg.CleanEnv()
		te.CreateFile("README.md", "# Test Project")
		gitAdd := exec.Command("git", "add", ".")
		gitAdd.Dir = te.Dir
		gitAdd.Env = cleanEnv
		require.NoError(te.t, gitAdd.Run())
		gitCommit := exec.Command("git", "commit", "-m", "Initial commit")
		gitCommit.Dir = te.Dir
		gitCommit.Env = cleanEnv
		require.NoError(te.t, gitCommit.Run())
	}

	// Default flags if none provided
	if len(flags) == 0 {
		if te.GitInitialized {
			// Use --repository and --branch flags to specify test library
			flags = []string{"--repository", te.TestLibraryURL, "--branch", "master", "--silent", "--skip-claude-injection"}
		} else {
			// No git, use --no-git flag
			flags = []string{"--no-git", "--silent", "--skip-claude-injection"}
		}
	}

	args := append([]string{"init"}, flags...)
	output, err := te.RunCommand(args...)
	require.NoError(te.t, err, "init should succeed: %s", output)
}

// LoadConfig loads the config using ConfigLoader
func (te *TestEnvironment) LoadConfig() (*config.Config, error) {
	loader, err := config.NewConfigLoaderWithWorkingDir(te.Dir)
	if err != nil {
		return nil, err
	}
	return loader.LoadConfig()
}

// CreateFile creates any file in the test environment
func (te *TestEnvironment) CreateFile(relativePath, content string) {
	te.t.Helper()
	fullPath := filepath.Join(te.Dir, relativePath)
	dir := filepath.Dir(fullPath)
	require.NoError(te.t, os.MkdirAll(dir, 0755))
	require.NoError(te.t, os.WriteFile(fullPath, []byte(content), 0644))
}

package cmd

import (
	"os"
	"os/exec"
	"path/filepath"
	"runtime"
	"strings"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// getSmokeTestBinaryPath builds the CLI binary once and returns the path.
func getSmokeTestBinaryPath(t *testing.T) string {
	t.Helper()

	_, filename, _, ok := runtime.Caller(0)
	require.True(t, ok, "could not get caller info")

	// e2e_smoke_test.go is in cli/cmd/, so go up one level to get cli/
	cliRoot := filepath.Join(filepath.Dir(filename), "..")
	cliRoot, err := filepath.Abs(cliRoot)
	require.NoError(t, err)

	binaryPath := filepath.Join(t.TempDir(), "ddx")
	buildCmd := exec.Command("go", "build", "-buildvcs=false", "-o", binaryPath, ".")
	buildCmd.Dir = cliRoot
	out, err := buildCmd.CombinedOutput()
	require.NoError(t, err, "go build failed: %s", string(out))
	require.NoError(t, os.Chmod(binaryPath, 0755))

	return binaryPath
}

// runInDir executes the binary with args in the given directory and returns combined output.
// It strips DDx-specific env vars so the subprocess uses only the isolated workDir state.
func runInDir(t *testing.T, binary, dir string, args ...string) (string, int) {
	t.Helper()
	cmd := exec.Command(binary, args...)
	cmd.Dir = dir
	// Build a clean environment: keep PATH/HOME/USER/TMPDIR but strip DDx overrides
	// so the binary resolves config and storage from dir, not from the parent shell.
	ddxOverrides := map[string]bool{
		"DDX_BEAD_DIR":          true,
		"DDX_BEAD_PREFIX":       true,
		"DDX_BEAD_BACKEND":      true,
		"DDX_LIBRARY_BASE_PATH": true,
	}
	for _, kv := range os.Environ() {
		key := kv
		if idx := strings.Index(kv, "="); idx >= 0 {
			key = kv[:idx]
		}
		if !ddxOverrides[key] {
			cmd.Env = append(cmd.Env, kv)
		}
	}
	out, err := cmd.CombinedOutput()
	output := string(out)

	exitCode := 0
	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			exitCode = exitErr.ExitCode()
		} else {
			exitCode = -1
		}
	}
	return output, exitCode
}

// TestE2ESmokeJourney validates the core onboarding journey end-to-end using
// the built binary in a fresh temp git directory.
func TestE2ESmokeJourney(t *testing.T) {
	if testing.Short() {
		t.Skip("Skipping E2E smoke test in short mode")
	}

	binary := getSmokeTestBinaryPath(t)

	// Create isolated temp directory with a git repo
	workDir := t.TempDir()

	gitCmds := [][]string{
		{"git", "init"},
		{"git", "config", "user.email", "smoke@example.com"},
		{"git", "config", "user.name", "Smoke Test"},
	}
	for _, args := range gitCmds {
		c := exec.Command(args[0], args[1:]...)
		c.Dir = workDir
		require.NoError(t, c.Run(), "git setup: %v", args)
	}

	// Create an initial commit so git has something to work with
	readmePath := filepath.Join(workDir, "README.md")
	require.NoError(t, os.WriteFile(readmePath, []byte("# Smoke Test\n"), 0644))
	for _, args := range [][]string{
		{"git", "add", "README.md"},
		{"git", "commit", "-m", "Initial commit"},
	} {
		c := exec.Command(args[0], args[1:]...)
		c.Dir = workDir
		require.NoError(t, c.Run(), "git commit: %v", args)
	}

	// TC-001: Init
	t.Run("TC-001-Init", func(t *testing.T) {
		testLibraryURL := "file://" + GetTestLibraryPath()
		out, code := runInDir(t, binary, workDir,
			"init",
			"--repository", testLibraryURL,
			"--branch", "master",
			"--silent",
			"--skip-claude-injection",
		)
		t.Logf("init output: %s", out)
		assert.Equal(t, 0, code, "ddx init should exit 0")
		assert.FileExists(t, filepath.Join(workDir, ".ddx", "config.yaml"))
	})

	// Seed a .md persona so persona commands can find it
	personasDir := filepath.Join(workDir, ".ddx", "plugins", "ddx", "personas")
	require.NoError(t, os.MkdirAll(personasDir, 0755))
	personaContent := `---
name: code-reviewer
roles: [code-reviewer]
description: Code reviewer
tags: [quality]
---

# Code Reviewer

You are a code reviewer.`
	require.NoError(t, os.WriteFile(
		filepath.Join(personasDir, "code-reviewer.md"),
		[]byte(personaContent),
		0644,
	))

	// TC-002: List
	t.Run("TC-002-List", func(t *testing.T) {
		out, code := runInDir(t, binary, workDir, "list")
		t.Logf("list output: %s", out)
		assert.Equal(t, 0, code, "ddx list should exit 0")
		// Output should contain at least one resource category
		hasCategory := strings.Contains(out, "Templates") ||
			strings.Contains(out, "Prompts") ||
			strings.Contains(out, "Personas") ||
			strings.Contains(out, "Mcp-Servers")
		assert.True(t, hasCategory, "list output should contain document categories; got: %s", out)
	})

	// TC-003: Doctor
	t.Run("TC-003-Doctor", func(t *testing.T) {
		out, code := runInDir(t, binary, workDir, "doctor")
		t.Logf("doctor output: %s", out)
		assert.Equal(t, 0, code, "ddx doctor should exit 0")
		assert.NotContains(t, strings.ToUpper(out), "ERROR", "doctor output should not contain ERROR")
	})

	// TC-004: Persona list
	t.Run("TC-004-PersonaList", func(t *testing.T) {
		out, code := runInDir(t, binary, workDir, "persona", "list")
		t.Logf("persona list output: %s", out)
		assert.Equal(t, 0, code, "ddx persona list should exit 0")
		assert.NotContains(t, out, "No personas found", "should list at least one persona")
		assert.Contains(t, out, "code-reviewer")
	})

	// TC-005: Persona bind
	t.Run("TC-005-PersonaBind", func(t *testing.T) {
		out, code := runInDir(t, binary, workDir, "persona", "bind", "code-reviewer", "code-reviewer")
		t.Logf("persona bind output: %s", out)
		assert.Equal(t, 0, code, "ddx persona bind should exit 0; output: %s", out)
	})

	// TC-006: Bead create
	t.Run("TC-006-BeadCreate", func(t *testing.T) {
		out, code := runInDir(t, binary, workDir, "bead", "create", "Smoke test", "--type", "task")
		t.Logf("bead create output: %s", out)
		assert.Equal(t, 0, code, "ddx bead create should exit 0")
		// Output should be a bead ID (non-empty trimmed string)
		assert.NotEmpty(t, strings.TrimSpace(out), "bead create should output a bead ID")
	})

	// TC-007: Bead list
	t.Run("TC-007-BeadList", func(t *testing.T) {
		out, code := runInDir(t, binary, workDir, "bead", "list")
		t.Logf("bead list output: %s", out)
		assert.Equal(t, 0, code, "ddx bead list should exit 0")
		assert.Contains(t, out, "Smoke test", "bead list should contain the created bead title")
	})
}

package workerprobe_test

import (
	"bufio"
	"encoding/json"
	"net/http/httptest"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"testing"
	"time"

	serverpkg "github.com/DocumentDrivenDX/ddx/internal/server"
)

// TestWorker_RealAttemptEvents_FlowToServer is the wired-in end-to-end
// proof for ADR-022 step 2: it stands up the production server HTTP path
// (httptest.Server wrapping a real serverpkg.Server), points the worker at
// it via the production server.addr discovery (XDG_DATA_HOME), spawns a
// real `ddx work --once` subprocess against a fixture project, and
// asserts that the worker's bead-attempt loop events appear in the
// server's derived view (the worker-events.jsonl log) within 5s.
//
// This exercises the entire wire: writeLoopEvent → loopSink → TeeJSONL →
// workerprobe.Probe → POST /api/workers/register + /api/workers/{id}/event
// (or /backfill on the immediate first probe before any events fire).
func TestWorker_RealAttemptEvents_FlowToServer(t *testing.T) {
	if testing.Short() {
		t.Skip("integration test: spawns ddx work subprocess")
	}

	// Use a 'standard' fixture (5 sample beads) so the loop has at least
	// one bead to claim → at least one bead-scoped event flows. We don't
	// require the bead to succeed; ddx work will emit loop.start +
	// bead.claimed before any harness invocation.
	// Build a fresh ddx binary from the current tree so the subprocess
	// includes the workerprobe wiring under test (cannot rely on $PATH ddx
	// being current). Build before NewFixtureRepo so the same binary seeds
	// the fixture, avoiding two builds.
	binDir := t.TempDir()
	binPath := filepath.Join(binDir, "ddx")
	build := exec.Command("go", "build", "-buildvcs=false", "-o", binPath, ".")
	build.Dir = repoCLIDir(t)
	if out, err := build.CombinedOutput(); err != nil {
		t.Fatalf("go build ddx: %v\n%s", err, out)
	}
	t.Setenv("DDX_BIN", binPath)

	proj := buildFixtureRepo(t, binPath, "standard")
	bin := binPath

	// Real server — same constructor, same Handler, same requireTrusted gate.
	srv := serverpkg.New(":0", proj)
	ts := httptest.NewServer(srv.Handler())
	defer ts.Close()

	// Production discovery path: write server.addr under XDG_DATA_HOME so
	// the worker subprocess (running with the same XDG_DATA_HOME) finds it
	// via serverpkg.ReadServerAddr.
	xdg := t.TempDir()
	addrDir := filepath.Join(xdg, "ddx")
	if err := os.MkdirAll(addrDir, 0o700); err != nil {
		t.Fatalf("mkdir addr dir: %v", err)
	}
	addrPath := filepath.Join(addrDir, "server.addr")
	addrPayload, _ := json.Marshal(map[string]any{
		"url": ts.URL,
		"pid": os.Getpid(), // alive so ReadServerAddr accepts it
	})
	if err := os.WriteFile(addrPath, addrPayload, 0o600); err != nil {
		t.Fatalf("write server.addr: %v", err)
	}

	// Spawn `ddx work --once`. We deliberately pass --no-review with the
	// required acknowledgement flag and a bogus harness so the worker exits
	// quickly after emitting loop.start + bead.claimed; the harness failure is
	// irrelevant to this test, which asserts only that events flowed through the
	// probe.
	cmd := exec.Command(bin, "work", "--once", "--no-review", "--no-review-i-know-what-im-doing",
		"--harness", "noop", "--project", proj)
	cmd.Env = append(os.Environ(),
		"XDG_DATA_HOME="+xdg,
		"HOME="+t.TempDir(),
	)
	cmd.Dir = proj
	out, err := cmd.CombinedOutput()
	t.Logf("ddx work exit: err=%v\noutput:\n%s", err, out)

	// Wait up to 5s for the server's worker-events.jsonl log to receive at
	// least one event mirrored from the worker subprocess.
	logPath := filepath.Join(proj, ".ddx", "server", "worker-events.jsonl")
	deadline := time.Now().Add(5 * time.Second)
	var lines []string
	for time.Now().Before(deadline) {
		lines = readLogLines(t, logPath)
		if len(lines) > 0 {
			break
		}
		time.Sleep(50 * time.Millisecond)
	}
	if len(lines) == 0 {
		t.Fatalf("no worker events appeared in %s within 5s; subprocess output:\n%s", logPath, out)
	}

	// Sanity-check: at least one mirrored event should be a loop.* or
	// bead.* envelope identifiable by the writeLoopEvent shape (kind field
	// in the loggedEvent wrapper).
	var kinds []string
	for _, line := range lines {
		var le struct {
			Kind string `json:"kind"`
		}
		_ = json.Unmarshal([]byte(line), &le)
		kinds = append(kinds, le.Kind)
	}
	t.Logf("mirrored event kinds: %v", kinds)
	hasExpected := false
	for _, k := range kinds {
		if strings.HasPrefix(k, "loop.") || strings.HasPrefix(k, "bead.") {
			hasExpected = true
			break
		}
	}
	if !hasExpected {
		t.Errorf("expected at least one loop.* or bead.* event mirrored, got kinds=%v", kinds)
	}
}

// repoCLIDir walks up from this file to find the cli/ directory (which
// holds go.mod). Used to build a fresh ddx binary for the integration test.
func repoCLIDir(t *testing.T) string {
	t.Helper()
	wd, err := os.Getwd()
	if err != nil {
		t.Fatalf("getwd: %v", err)
	}
	dir := wd
	for {
		if _, err := os.Stat(filepath.Join(dir, "go.mod")); err == nil {
			return dir
		}
		parent := filepath.Dir(dir)
		if parent == dir {
			t.Fatalf("could not locate go.mod from %s", wd)
		}
		dir = parent
	}
}

// buildFixtureRepo runs scripts/build-fixture-repo.sh with the supplied ddx
// binary and profile, returning the created project root.
func buildFixtureRepo(t *testing.T, bin, profile string) string {
	t.Helper()
	root := filepath.Dir(repoCLIDir(t))
	script := filepath.Join(root, "scripts", "build-fixture-repo.sh")
	dest := t.TempDir()

	cmd := exec.Command("bash", script, dest, "--profile", profile)
	cmd.Env = append(os.Environ(), "DDX_BIN="+bin)
	out, err := cmd.CombinedOutput()
	if err != nil {
		t.Fatalf("build-fixture-repo.sh failed (profile=%s): %v\n%s", profile, err, out)
	}
	return dest
}

// readLogLines returns each newline-separated line of the file at path,
// or nil if the file does not yet exist.
func readLogLines(t *testing.T, path string) []string {
	t.Helper()
	f, err := os.Open(path)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		t.Fatalf("open %s: %v", path, err)
	}
	defer f.Close()
	var out []string
	sc := bufio.NewScanner(f)
	for sc.Scan() {
		out = append(out, sc.Text())
	}
	return out
}

